<?php
namespace App\Services\Security;
use App\Models\{SecurityAuditExportRetentionJob,SecurityGovernanceNotification,SecurityIncident,User};
class SecurityExportDeletionPolicyService{public function getReadiness():array{$blockers=[];if(!file_exists(base_path('docs/SECURITY_AUDIT_EXPORT_RETENTION_POLICY.md')))$blockers[]='Approved retention policy document is missing.';if(!SecurityAuditExportRetentionJob::where('status','dry_run_completed')->exists())$blockers[]='No export retention dry-run exists.';if(!SecurityAuditExportRetentionJob::where('status','approved')->whereColumn('requested_by_id','!=','approved_by_id')->exists())$blockers[]='No two-person approved export retention job exists.';if(SecurityGovernanceNotification::where('status','open')->where('severity','critical')->exists())$blockers[]='Open critical governance notification exists.';if(SecurityIncident::whereNotIn('status',['resolved','cancelled'])->where('severity','critical')->exists())$blockers[]='Open critical security incident exists.';$blockers[]='Physical export deletion is disabled by default.';return ['ready'=>false,'enabled'=>false,'blockers'=>$blockers];}public function canEnablePhysicalDeletion(User $a):array{$r=$this->getReadiness();if(!$a->can('admin.security.export_deletion_policy.manage'))$r['blockers'][]='Export deletion policy management permission is required.';return $r;}public function requestEnablePhysicalDeletion(User $a,string $reason):array{return $this->canEnablePhysicalDeletion($a);}public function disablePhysicalDeletion(User $a,string $reason):array{return ['enabled'=>false,'reason'=>$reason,'blockers'=>['Physical export deletion remains disabled.']];}}
